class UnitMismatchError(Exception): pass

class DimensionalValue:
    def __init__(self, value, unit):
        self.value = value; self.unit = unit
    def add(self, other):
        if self.unit != other.unit:
            raise UnitMismatchError(
                f'Cannot add {self.unit} + {other.unit}')
        return DimensionalValue(self.value+other.value, self.unit)
